# === SEO ============================================================================
# Two extensions cooperate:
#   - Description2 extracts a per-page <meta name="description"> from the article's
#     leading paragraph. WikiSEO reads its output when present.
#   - WikiSEO emits the full OG + Twitter Card + Schema.org JSON-LD + canonical-link
#     surface. Per-page customisation is via the {{#seo:...}} parser function in
#     wikitext. The site-wide defaults below cover everything not page-specific.
#
# Per-page customisation example (used by Cargo templates once Phase 3 content lands):
#   {{#seo:
#     |title=שי אליאס - פרופיל שחקן
#     |title_mode=replace
#     |description=שחקן הפועל באר שבע מאז 2018, רגל ימין דומיננטית, ...
#     |image=ShayElias.jpg
#     |image_alt=שי אליאס בעונת 2024/25
#     |type=Person
#     |published_time=2018-08-15
#   }}
# WikiSEO emits the matching og:*, twitter:*, and Schema.org JSON-LD blocks. For
# SportsTeam / SportsEvent / Person, set |type= and WikiSEO maps to the correct
# Schema.org type.
wfLoadExtension( 'Description2' );
wfLoadExtension( 'WikiSEO' );
$wgEnableMetaDescriptionFunctions = true; // expose {{#description2:}} for explicit overrides

# Site-wide SEO defaults
$wgEnableCanonicalServerLink = true;                      // <link rel="canonical"> everywhere
# og:image needs a fully-qualified URL - the OG spec requires it and most social platforms
# silently drop relative refs. We hardcode the prod URL because this config block runs
# BEFORE the environment-specific block where $wgServer is set; the file is anyway production-
# only meaningful (dev/localhost URLs aren't socially shared).
$wgWikiSeoDefaultImage       = 'https://wiki7.co.il/assets/social-share.png'; // 1200x630 PNG, CDK->S3->CF
$wgTwitterCardType           = 'summary_large_image';      // Use the large preview variant
# Organization.logo / Article.image fallback for Schema.org is fed by adding a PNG entry
# to $wgLogos below (next to the SVG entries) - WikiSEO filters $wgLogos by extension and
# rejects SVG. Setting $wgLogo (singular) wouldn't help here because getWikiLogo only
# falls back to it when $wgLogos is unset.

# Site-wide WikiSEO metadata defaults. The WikiSEOPreAddMetadata hook fires before
# WikiSEO's OG/Twitter/Schema.org generators emit tags; we fill in missing keys so the
# default behaviour is brand-forward, og:type is correct, and og:locale is he_IL.
# Per-page {{#seo:...}} calls still win - we only set keys that weren't already provided.
$wgWiki7Tagline = 'אנציקלופדיית הפועל באר שבע';
$wgHooks['WikiSEOPreAddMetadata'][] = function ( array &$metadata ) {
    global $wgWiki7Tagline, $wgSitename;

    // og:title - we want the brand name "ויקישבע" to appear on every share preview, on
    // every page. Different patterns per page type:
    //   - Main page: "ויקישבע - אנציקלופדיית הפועל באר שבע" (brand first, then descriptive
    //     tagline; the bare page title "עמוד ראשי" alone is bland).
    //   - Article pages: "<page name> - ויקישבע" (standard SEO pattern, page-specific
    //     identifier first, site brand at the end).
    //
    // WikiSEO's title_mode='append' looks like it should do this but it doesn't - it only
    // affects the HTML <title> element, NOT og:title. The OG generator's title-emission
    // path is:
    //   1) addTitleMeta() emits og:title using $out->getTitle()->getPrefixedText()
    //   2) the generator's foreach loop then EMITS og:title AGAIN from metadata['title']
    //      via addHeadItem with the same key, overwriting step 1
    // So step-2 wins, and og:title ends up equal to whatever metadata['title'] holds. To
    // produce the brand-inclusive titles above we build the full string ourselves and
    // hand it to WikiSEO via metadata['title'] with title_mode='replace'.
    if ( !isset( $metadata['title'] ) ) {
        $title         = \RequestContext::getMain()->getTitle();
        $pageTitleText = $title ? $title->getPrefixedText() : '';

        if ( $title && $title->isMainPage() ) {
            $metadata['title'] = $wgSitename . ' - ' . $wgWiki7Tagline;
        } elseif ( $pageTitleText !== '' ) {
            $metadata['title'] = $pageTitleText . ' - ' . $wgSitename;
        } else {
            $metadata['title'] = $wgSitename;
        }
        $metadata['title_mode'] = 'replace';
    }

    // og:type - lowercase per the OG spec ('website', 'article'). WikiSEO REL1_45 reads
    // $metadata['type'] for BOTH og:type AND Schema.org @type (single shared key, no
    // separate schema_type; verified in Generator/Plugins/SchemaOrg.php and OpenGraph.php).
    // The two standards clash on casing (OG = lowercase, Schema.org = CamelCase). We resolve
    // it by emitting lowercase here for og:type correctness, and the
    // OutputPageAfterGetHeadLinksArray hook below post-processes the JSON-LD <script> tag to
    // CamelCase the @type field only.
    //
    // Why split rather than just CamelCase both:
    //   - Mastodon's link_details_extractor matches `og:type == 'article'` exactly (case
    //     sensitive); CamelCase misses the article-styled card variant for a generic link
    //     card. Other OG consumers (FB, Twitter, Slack, Lemmy, Misskey) either don't read
    //     og:type or pass it through; only Mastodon's richer rendering is measurably impacted.
    //   - Schema.org JSON-LD context is case-sensitive IRI matching ('schema:WebSite' is a
    //     defined term, 'schema:website' isn't), so CamelCase is required for Google Rich
    //     Results eligibility.
    // (Phase 2.5c Round 1 Finding 3, rolled into 2.5b.)
    if ( !isset( $metadata['type'] ) ) {
        $title = \RequestContext::getMain()->getTitle();
        $metadata['type'] = ( $title && $title->isMainPage() ) ? 'website' : 'article';
    }

    // og:locale - Hebrew Israel; matches $wgLanguageCode='he' and the RTL skin direction.
    if ( !isset( $metadata['locale'] ) ) {
        $metadata['locale'] = 'he_IL';
    }
};

# Schema.org @type CamelCase fix. WikiSEO emits OG meta tags AND a JSON-LD <script> from the
# same metadata['type'] key, so we can't fix one without the other from the metadata array.
# We emit lowercase for og:type (the hook above) and post-process the JSON-LD <script> tag
# here to give Schema.org its canonical CamelCase @type.
#
# WikiSEO's PageHooks::onBeforePageDisplay calls SchemaOrg generator → addHeadItem(
# 'jsonld-metadata', '<script>...</script>'). We hook OutputPageAfterGetHeadLinksArray
# which fires LATER in the render pipeline (during the head-rendering pass, after all
# BeforePageDisplay handlers have run), so the head item already exists when we run.
# addHeadItem() overwrites by key (OutputPage::$mHeadItems[$name] = $value), so re-calling
# it with the same 'jsonld-metadata' key replaces WikiSEO's emission with our fixed value.
# We don't mutate the $tags array directly because the JSON-LD <script> is in $mHeadItems,
# not in the head-links array that $tags carries.
$wgHooks['OutputPageAfterGetHeadLinksArray'][] = function ( array &$tags, OutputPage $out ) {
    $items = $out->getHeadItemsArray();
    if ( !isset( $items['jsonld-metadata'] ) ) {
        return;
    }
    $original = $items['jsonld-metadata'];
    $fixed = strtr( $original, [
        '"@type":"website"' => '"@type":"WebSite"',
        '"@type":"article"' => '"@type":"Article"',
    ] );
    if ( $fixed !== $original ) {
        $out->addHeadItem( 'jsonld-metadata', $fixed );
    }
};

# Fallback description for pages where neither Description2 (no leading paragraph) nor
# a {{#seo:description=...}} call produced one - most commonly the main page, whose
# wikitext is template-only. The hook idempotently skips when something else already
# emitted a description, so per-page descriptions always win when they exist.
$wgWiki7FallbackDescription = 'אנציקלופדיית הפועל באר שבע - היסטוריה, שחקנים, גביעים ואוהדים';
$wgHooks['BeforePageDisplay'][] = function ( OutputPage $out, Skin $skin ) {
    global $wgWiki7FallbackDescription;
    foreach ( $out->getHeadItemsArray() as $item ) {
        // Skip the fallback if WikiSEO / Description2 / a manual <meta> already set one.
        if ( preg_match( '/(name|property)="(description|og:description)"/i', $item ) ) {
            return;
        }
    }
    $esc = htmlspecialchars( $wgWiki7FallbackDescription, ENT_QUOTES, 'UTF-8' );
    $out->addHeadItem( 'wiki7-fallback-description',
          "\t<meta name=\"description\" content=\"{$esc}\">\n"
        . "\t<meta property=\"og:description\" content=\"{$esc}\">\n"
        . "\t<meta name=\"twitter:description\" content=\"{$esc}\">\n" );
};

