$wgLogos = [
	'1x' => "$wgResourceBasePath/assets/logo-white.svg",
	'icon' => "$wgResourceBasePath/assets/logo-white.svg",
	// WikiSEO's Schema.org generator reads $wgLogos for the Organization.logo and
