	// filters by extension and ONLY accepts jpg/jpeg/png/gif/webp; SVG is rejected,
	// so the SVG entries above were producing empty arrays in the JSON-LD output.
	// The 'wikiseo' key isn't read by the skin (it pulls '1x' and 'icon' only); it
	// exists so the Schema.org generator finds a real bitmap URL to emit.
	'wikiseo' => 'https://wiki7.co.il/assets/social-share.png',
];

##
## Favicon + Apple touch icon
##
# Browser tab, bookmark icon, and iOS/Android home screen. Modern browsers prefer the SVG
# variant (crisp at every tab DPI, ~7 KB) and fall back to the multi-resolution ICO. iOS
# uses the 180x180 PNG for home-screen bookmarks. All three assets are generated from the
# same brand-red + white-logo recipe as social-share.png.
#
# - $wgFavicon emits the legacy <link rel="shortcut icon"> for older browsers.
# - The BeforePageDisplay hook adds the modern <link rel="icon" type="image/svg+xml"> and
#   the <link rel="apple-touch-icon"> tags, both of which MW core doesn't emit.
# - The Dockerfile also copies favicon.ico to /var/www/html/favicon.ico for tools that
#   auto-fetch /favicon.ico without parsing the HTML (bookmark scrapers, RSS readers,
#   link-preview generators).
$wgFavicon = '/assets/favicon.ico';

$wgHooks['BeforePageDisplay'][] = function ( OutputPage $out, Skin $skin ) {
	global $wgSitename, $wgWiki7Tagline;

	$out->addLink( [
		'rel'  => 'icon',
		'type' => 'image/svg+xml',
		'href' => '/assets/favicon.svg',
	] );
	$out->addLink( [
		'rel'   => 'apple-touch-icon',
		'href'  => '/assets/apple-touch-icon.png',
		'sizes' => '180x180',
	] );

	// Force-set the HTML <title> to match og:title. WikiSEO's modifyPageTitle runs BEFORE
	// the WikiSEOPreAddMetadata hook fires, so the title we put into metadata['title']
	// via that hook never reaches modifyPageTitle - it returns early on the missing key
	// and the bare default <title> (just $wgSitename on the main page, or "<page> - <site>"
	// elsewhere) leaks through. Setting the HTML title ourselves at BeforePageDisplay
	// time fires AFTER WikiSEO's hook completes and BEFORE the skin reads getHTMLTitle
	// to compose the <title> element, so the value sticks.
	//
	// Per-page {{#seo:title=...}} overrides still win: that parser-function call writes
	// the 'title' value to the page_props table, modifyPageTitle reads it from there and
	// calls setHTMLTitle BEFORE our hook runs, and we detect the page-prop and skip our
	// force-set so we don't clobber the editor's choice.
	$title = $out->getTitle();
	if ( !$title ) {
		return;
	}
	$pageProps = \MediaWiki\MediaWikiServices::getInstance()->getPageProps();
	$customTitleProp = $pageProps->getProperties( $title, 'title' );
	if ( !empty( $customTitleProp ) ) {
		return;
	}
	$htmlTitle = $title->isMainPage()
		? $wgSitename . ' - ' . $wgWiki7Tagline
		: $title->getPrefixedText() . ' - ' . $wgSitename;
	$out->setHTMLTitle( $htmlTitle );
};

##
## Monitoring
##
$wgPingback = true; // Help MediaWiki devs by sending anonymous usage stats

##
## Environment-specific settings
##
# Switches behavior based on WIKI_ENV ("production" vs "development")

if ( getenv('WIKI_ENV') === 'production' ) {
    // Production mode
    $wgServer = "https://wiki7.co.il";
    $wgCanonicalServer = "https://wiki7.co.il";
    $wgCookieSecure = true; // Only transmit cookies over HTTPS

    // === Job queue — drained out-of-band, not inline on web requests =======================
    // Inline runs (the default $wgJobRunRate = 1) bolt one job onto every web hit, adding
    // latency to whichever unlucky user triggered the page; behind CloudFront the origin
    // sees few hits to begin with, so refreshLinks / Cargo population would drain slowly.
    // The EC2 UserData (compute-stack.ts) installs a host-side cron that calls runJobs.php
    // every minute. Production-only because the host cron only exists on the EC2; local
    // docker-compose dev keeps MW's default ($wgJobRunRate = 1) so jobs drain inline on
    // request without ceremony.
    $wgJobRunRate = 0;

    // === CDN awareness =====================================================================
    // $wgUseCdn = true tells MW it's behind a shared cache: it emits Vary: Cookie correctly,
    // skips internal cache-key choices that assume direct-to-origin, and is the prerequisite
    // for CloudFront actually honoring the s-maxage MW emits.
    //
    // Phase 2.5b (this PR) switched CloudFront's default behavior off CachePolicy.CACHING_DISABLED
    // onto the new Wiki7DynamicHtml cache policy (cookie-aware, MinTTL=0 so origin Cache-Control
    // is trusted, MaxTTL=1d as a safety cap). MW emits `Cache-Control: s-maxage=$wgCdnMaxAge,
    // max-age=0` for anon responses and `Cache-Control: private, no-cache` for logged-in
    // responses, so anon HTML caches at the edge for $wgCdnMaxAge seconds and logged-in HTML
    // bypasses the cache. See cdk/lib/cloudfront-stack.ts for the cookie-keying details.
    $wgUseCdn = true;

    // $wgCdnMaxAge — bounded worst-case staleness for edits.
    //
    // MW default is 18000s (5h). For Phase 3 (content + data pipeline, edit-heavy) we want
    // edits to be visible to anon readers reasonably quickly without standing up edit-driven
    // CloudFront invalidation (Lambda + IAM + AWS SDK PHP integration + per-edit cost).
    //
    // Options considered:
    //   (a) Default 5h, no invalidation       — simplest, but 5h is too stale during a pipeline run
    //   (b) Shorten to 600s (10 min)          — bounded staleness, no new infra, slight hit-ratio cost
    //   (c) Default 5h + CreateInvalidation   — sub-second edit→fresh, but real infra cost
    //
    // Chose (b). 10-min worst-case is fine for both human edits and pipeline review; the
    // cache-hit-ratio cost vs option (c) is small at our traffic volume. Revisit and add (c)
    // in Phase 4 if real edit cadence makes 10-min staleness painful. The CloudFront cache
    // policy's MaxTTL is 1d (clamps origin even if this ever gets set higher accidentally).
    $wgCdnMaxAge = 600;

    // $wgRateLimits — left at MW defaults intentionally.
    //
    // Pre-PR #38 every viewer looked like a CloudFront edge IP, so per-IP rate limits were
    // nonsense (everyone shared one IP at the MW layer). After #38 + 2.5d the per-IP buckets
    // actually apply per real client. MW 1.45 defaults: edit=8/60s (ip/newbie), 90/60s (user);
    // move/linkpurge/purge similar.
    //
    // For the data-pipeline bot, see the universal `$wgGroupPermissions['bot']['noratelimit']`
    // grant above the production block — applies in both local + prod since Wiki7Bot is a bot
    // regardless of environment.

    // Real client IP recovery behind CloudFront. CloudFront's origin request policy
    // (ALL_VIEWER_AND_CLOUDFRONT_2022, set in cloudfront-stack.ts) adds the
    // 'CloudFront-Viewer-Address' header. CloudFront populates it from the actual TCP
    // viewer connection and strips any client-supplied value, so it cannot be spoofed.
    //
    // We overwrite $_SERVER['REMOTE_ADDR'] BEFORE MW boots: MW core reads REMOTE_ADDR
    // directly in WebRequest::getIP() and only consults X-Forwarded-For when REMOTE_ADDR
    // is a trusted proxy (per $wgCdnServersNoPurge). Setting REMOTE_ADDR to the real viewer
    // IP makes RecentChanges, IP blocks, and abuse throttling work correctly without
    // having to track CloudFront's dynamic IP ranges in $wgCdnServersNoPurge.
    //
    // Format from CloudFront docs: "<ip>:<port>" for IPv4, "<ip>:<port>" with the IP in
    // square brackets for IPv6 ("[2001:db8::1]:443"). We strip the port and the brackets,
    // then validate the result with FILTER_VALIDATE_IP before assignment — CloudFront
    // should never emit a malformed value, but a pathological one (e.g. "[]:80") would
    // produce an empty string we don't want to write into REMOTE_ADDR.
    if ( !empty( $_SERVER['HTTP_CLOUDFRONT_VIEWER_ADDRESS'] ) ) {
        $cfViewer  = $_SERVER['HTTP_CLOUDFRONT_VIEWER_ADDRESS'];
        $candidate = null;
        if ( $cfViewer[0] === '[' ) {
            // IPv6: "[2001:db8::1]:443" -> "2001:db8::1"
            $end = strpos( $cfViewer, ']' );
            if ( $end !== false ) {
                $candidate = substr( $cfViewer, 1, $end - 1 );
            }
        } else {
            // IPv4: "1.2.3.4:56789" -> "1.2.3.4"
            $colon = strrpos( $cfViewer, ':' );
            $candidate = $colon !== false
                ? substr( $cfViewer, 0, $colon )
                : $cfViewer;
        }
        if ( $candidate !== null && filter_var( $candidate, FILTER_VALIDATE_IP ) !== false ) {
            $_SERVER['REMOTE_ADDR'] = $candidate;
        }
    }
    // Deliberately NOT setting $wgCdnServersNoPurge: CloudFront's edge IP ranges are
    // dynamic (the AmazonIpSpaceChanged SNS topic publishes updates) and hard-coding a
    // snapshot would silently rot. Since we override REMOTE_ADDR above, MW never needs
    // to walk XFF, so the trusted-proxy list isn't load-bearing here.
    
    // Error handling
    $wgShowExceptionDetails = false; // Hide internal error details for security
    $wgDebugToolbar = false; // Should be false in production for security
    
    // Caching settings
    $wgCachePages = true; // Enable page caching
    $wgEnableParserCache = true; // Enable parsed output cache
    if ( getenv( 'REDIS_HOST' ) ) {
        // Sidecar Redis container - shared across all PHP workers (unlike APCu,
        // which is per-process). Big speedup on ParserOutput hits because every
        // worker reuses the same parsed page tree.
        $wgObjectCaches['redis'] = [
            'class'      => 'RedisBagOStuff',
            'servers'    => [ getenv( 'REDIS_HOST' ) . ':6379' ],
            'persistent' => true,
        ];
        $wgMainCacheType    = 'redis';
        $wgParserCacheType  = 'redis';
        $wgMessageCacheType = 'redis';
        $wgSessionCacheType = 'redis';
    } else {
        // Fallback for environments without Redis available.
        $wgMainCacheType   = CACHE_ACCEL;
        $wgParserCacheType = CACHE_ACCEL;
    }
    $wgCacheDirectory = "/tmp"; // Use local tmp dir for cache if needed
    
    // Resource paths
    $wgLoadScript = 'https://wiki7.co.il/load.php';
    $wgExtensionAssetsPath = 'https://wiki7.co.il/extensions';
    $wgResourceBasePath = $wgScriptPath;
    
    // Logging
    $wgDebugLogGroups['FileOperation'] = 'php://stderr'; // Log file operations to stderr
    
    // S3 for file storage - this requires AWS extension to be installed
    if (getenv('S3_BUCKET_NAME')) {
        # Load AWS extension
        wfLoadExtension( 'AWS' );

        # Credentials come from the EC2 instance role via IMDSv2 (no explicit $wgAWSCredentials).
        # The AWS SDK PHP credential provider chain auto-discovers in this order:
        #   ECS task role → EC2 instance metadata → env vars → ~/.aws/credentials
        # Override only if explicit access keys are present in the environment (e.g. local dev).
        if (getenv('AWS_ACCESS_KEY_ID') && getenv('AWS_SECRET_ACCESS_KEY')) {
            $wgAWSCredentials = [
                'key'    => getenv('AWS_ACCESS_KEY_ID'),
                'secret' => getenv('AWS_SECRET_ACCESS_KEY'),
                'token'  => false,
            ];
        }

        # S3 configuration
        $wgAWSRegion = 'il-central-1';
        $wgAWSBucketName = getenv('S3_BUCKET_NAME');
        
        # This is the key setting that fixes the regional endpoint issue
        # It tells MediaWiki to serve files through your CloudFront/custom domain
        $wgAWSBucketDomain = 'https://wiki7.co.il';

        # Subdirectory within the bucket where files are stored
        $wgAWSBucketTopSubdirectory = "/images";
        
        # Set paths for direct S3 access (fallback if CloudFront is unavailable)
        $wgUploadPath = 'https://' . $wgAWSBucketName . '.s3.il-central-1.amazonaws.com/images';

        # You can add CloudWatch logging for S3 operations if needed
        # $wgAWSLogging = true;
    } else {
        # Fall back to local file system if S3 bucket name is not provided
        $wgUploadDirectory = '/var/www/html/images';
        $wgUploadPath = 'https://wiki7.co.il/images';
        $wgStylePath = 'https://wiki7.co.il/skins';
    }
} else {
    // Development mode
    $wgServer = "http://localhost:8080";
    
    // Error handling - verbose in development
    $wgShowExceptionDetails = true; // Show full error stack traces
    $wgShowDBErrorBacktrace = true; // Show DB error backtraces
    $wgDebugToolbar = true; // Enable debug toolbar in UI
    $wgDevelopmentWarnings = true; // Show PHP notices
    
    // Caching - disabled in development for easier debugging
    $wgCachePages = false; // Disable page caching for live changes
    $wgEnableParserCache = false; // Disable parsed output cache
    $wgMainCacheType = CACHE_NONE; // No object caching
    $wgParserCacheType = CACHE_NONE;
    $wgCacheDirectory = false; // Disable file cache
    
    // Logging
    $wgDebugLogFile = "/tmp/mediawiki-debug.log"; // Log debug to file
    
    // Local file storage in development
    $wgUploadDirectory = '/var/www/html/images';
    $wgUploadPath = '/images';

    // Resource loader debug
    $wgResourceLoaderDebug = true;
}

# --- End of environment-specific settings ---